const aiResponse = $input.first().json;

let content = aiResponse.message?.content 
  || aiResponse.choices?.[0]?.message?.content 
  || aiResponse.content
  || aiResponse.text
  || aiResponse;

let parsed;
if (typeof content === 'object' && content !== null && content.sql) {
  parsed = content;
} else {
  let str = typeof content === 'string' ? content : JSON.stringify(content);
  str = str.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

  try {
    parsed = JSON.parse(str);
  } catch (e) {
    if (str.toLowerCase().startsWith('select') || str.toLowerCase().startsWith('with')) {
      parsed = { sql: str, explanation: 'Raw SQL returned' };
    } else {
      throw new Error('Cannot parse LLM response: ' + str.substring(0, 300));
    }
  }
}

const sql = (parsed.sql || '').trim();

if (!sql) {
  throw new Error('No SQL in response: ' + JSON.stringify(parsed).substring(0, 300));
}

const sqlLower = sql.toLowerCase();
const forbidden = ['drop', 'delete', 'update', 'insert', 'alter', 'truncate', 'create', 'grant', 'revoke'];
for (const word of forbidden) {
  if (new RegExp(`\\b${word}\\b`).test(sqlLower)) {
    throw new Error(`Query rejected: forbidden keyword "${word}"`);
  }
}

if (!sqlLower.startsWith('select') && !sqlLower.startsWith('with')) {
  throw new Error('Query must start with SELECT or WITH. Got: ' + sql.substring(0, 200));
}

return [{
  json: {
    sql: sql,
    explanation: parsed.explanation || '',
    user_question: $('Extract Question').first().json.user_question,
    channel: $('Extract Question').first().json.channel,
    attempt: $('Extract Question').first().json.attempt
  }
}];

const items = $input.all();
const firstItem = items[0]?.json;

const validator = $('SQL Validator').first().json;

if (firstItem?.error || (items.length === 1 && firstItem?.error !== undefined)) {
  return [{
    json: {
      success: false,
      error: firstItem.error || 'Unknown SQL error',
      sql: validator.sql,
      user_question: validator.user_question,
      channel: validator.channel,
      attempt: validator.attempt
    }
  }];
}

const rows = items.map(i => i.json).filter(r => r && !r.error);
const explanation = validator.explanation;

if (rows.length === 0) {
  return [{
    json: {
      success: true,
      text: `Query ran but returned no results.\n\n_${explanation}_`,
      rows: [],
      channel: validator.channel,
      sql: validator.sql
    }
  }];
}

const headers = Object.keys(rows[0]);
let table = '```\n';
table += headers.join(' | ') + '\n';
table += headers.map(() => '---').join(' | ') + '\n';
rows.slice(0, 10).forEach(row => {
  table += headers.map(h => {
    const v = row[h];
    if (v === null) return 'NULL';
    if (typeof v === 'number') return Number.isInteger(v) ? String(v) : v.toFixed(2);
    return String(v).slice(0, 30);
  }).join(' | ') + '\n';
});
table += '```';

const text = `*Results* (${rows.length} rows)\n\n${table}\n\n_${explanation}_`;

return [{
  json: {
    success: true,
    text,
    rows,
    channel: validator.channel,
    sql: validator.sql
  }
}];

