const currentAttempt = $('Format Results').first().json.attempt || 1;

if (currentAttempt >= 3) {
  return [{
    json: {
      success: true,
      text: `Sorry, I couldn't generate a valid query after 3 attempts.\n\nLast error: ${$('Format Results').first().json.error}`,
      rows: [],
      channel: $('Format Results').first().json.channel,
      sql: $('Format Results').first().json.sql,
      giveUp: true
    }
  }];
}

const aiResponse = $input.first().json;
let content = aiResponse.message?.content 
  || aiResponse.choices?.[0]?.message?.content 
  || aiResponse.content
  || aiResponse;

let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error('Fixer did not return valid JSON');
}

return [{
  json: {
    sql: parsed.sql,
    explanation: parsed.explanation,
    user_question: $('Format Results').first().json.user_question,
    channel: $('Format Results').first().json.channel,
    attempt: currentAttempt + 1
  }
}];

const data = $input.first().json;
const rows = data.rows || [];

if (rows.length < 3) {
  return [{ json: { ...data, chartUrl: null } }];
}

const headers = Object.keys(rows[0]);
const valueKey = headers.find(h => typeof rows[0][h] === 'number' && h !== headers[0]);

if (!valueKey) {
  return [{ json: { ...data, chartUrl: null } }];
}

const labelKey = headers[0];

const config = {
  type: 'bar',
  data: {
    labels: rows.slice(0, 15).map(r => String(r[labelKey]).slice(0, 20)),
    datasets: [{
      label: valueKey,
      data: rows.slice(0, 15).map(r => r[valueKey]),
      backgroundColor: '#4F46E5'
    }]
  },
  options: {
    title: { display: true, text: `${valueKey} by ${labelKey}` },
    legend: { display: false }
  }
};

const chartUrl = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(config))}&width=600&height=400&backgroundColor=white`;

return [{ json: { ...data, chartUrl } }];
